const path = require('path');
const ExcelJS = require('exceljs');

async function readAndWriteExcelFile() {
  try {
    // Specify the path to your input Excel file
    const inputFilePath = path.resolve(__dirname, './anish.xlsx');
    console.log('Input file path:', inputFilePath);

    // Create a new Excel workbook using exceljs
    const workbook = new ExcelJS.Workbook();
    
    // Read the Excel file
    await workbook.xlsx.readFile(inputFilePath);
    console.log('Workbook:', workbook);

    // Find the object with the name 'Company Information'
    const companyInformationSheet = workbook.getWorksheet('Company Information');

    // Check if the sheet is found
    if (!companyInformationSheet) {
      throw new Error('Company Information sheet not found in the Excel file.');
    }

    // Create a new Excel workbook and worksheet using exceljs
    const newWorkbook = new ExcelJS.Workbook();
    const newWorksheet = newWorkbook.addWorksheet('Company Information');

    // Copy data and styles from the original sheet to the new sheet
    companyInformationSheet.eachRow(row => {
      newWorksheet.addRow(row.values);
    });

    // Specify the path to your output Excel file
    const outputFilePath = path.resolve(__dirname, './output.xlsx');

    // Write the new Excel file using exceljs
    await newWorkbook.xlsx.writeFile(outputFilePath);

    console.log(`New Excel file created at: ${outputFilePath}`);
  } catch (error) {
    console.error('An error occurred:', error.message);
  }
}

// Call the function to read and write the Excel file
readAndWriteExcelFile();

